  let junctionCount = 0;
  for (const [className, spellNames] of Object.entries(classSpellData)) {
    const cls = await prisma.class.findFirst({ where: { name: { equals: className, mode: 'insensitive' } } });
    if (!cls) { console.warn(`    ⚠ Class not found: ${className}`); continue; }

    for (const spellName of spellNames) {
      const spell = await prisma.spell.findFirst({ where: { name: { equals: spellName, mode: 'insensitive' } } });
      if (!spell) continue; // spell not in DB yet — skip silently
      await prisma.classSpell.upsert({
        where:  { class_id_spell_id: { class_id: cls.class_id, spell_id: spell.spell_id } },
        update: {},
        create: { class_id: cls.class_id, spell_id: spell.spell_id },
      });
      junctionCount++;
    }
  }
  console.log(`    ✓ ${junctionCount} class-spell links seeded.`);
